import{_ as t,o as x,c as r,a4 as a}from"./chunks/framework.ChErgFjV.js";const s="/my-knowledge/assets/quadratic-case01.CO0sw9hY.png",o="/my-knowledge/assets/quadratic-case02.BhzE0JSn.png",n="/my-knowledge/assets/quadratic-case03.BWHd4G8r.png",e="/my-knowledge/assets/quadratic-case04.Clo6KlSU.png",d="/my-knowledge/assets/quadratic-case05.iJLcm-B4.png",g="/my-knowledge/assets/quadratic-case06.Cf7wpzjq.png",l="/my-knowledge/assets/quadratic-case07.B3vuW7pF.png",i="/my-knowledge/assets/quadratic-case08.D9q-zzsq.png",c="/my-knowledge/assets/quadratic-case09.k8C6Ak4t.png",h="/my-knowledge/assets/quadratic-case10.CZ5hg-12.png",_=JSON.parse('{"title":"二次函数 — 广州中考真题案例与解析","description":"","frontmatter":{"title":"二次函数 — 广州中考真题案例与解析","date":"2026-07-03T00:00:00.000Z","tags":["二次函数","广州中考","压轴题"]},"headers":[],"relativePath":"study/junior-math/exam/quadratic-geometry.md","filePath":"study/junior-math/exam/quadratic-geometry.md","lastUpdated":1783652711000}'),m={name:"study/junior-math/exam/quadratic-geometry.md"};function P(y,p,A,u,C,M){return x(),r("div",null,[...p[0]||(p[0]=[a('<h1 id="二次函数-—-广州中考真题案例与解析" tabindex="-1">二次函数 — 广州中考真题案例与解析 <a class="header-anchor" href="#二次函数-—-广州中考真题案例与解析" aria-label="Permalink to &quot;二次函数 — 广州中考真题案例与解析&quot;">​</a></h1><blockquote><p>二次函数是广州中考压轴题的首选板块，每年必考，分值 12-15 分。</p><p>难度标注：⭐ 基础 | ⭐⭐ 中等 | ⭐⭐⭐ 较难 | ⭐⭐⭐⭐ 压轴</p></blockquote><hr><h2 id="案例-1-求二次函数解析式-⭐" tabindex="-1">案例 1：求二次函数解析式 ⭐ <a class="header-anchor" href="#案例-1-求二次函数解析式-⭐" aria-label="Permalink to &quot;案例 1：求二次函数解析式 ⭐&quot;">​</a></h2><p><img src="'+s+'" alt="案例1示意图"></p><p><strong>【题目】</strong> 已知抛物线经过点 A(0, 3)、B(1, 0)、C(3, 0)，求抛物线解析式。</p><p><strong>【解析】</strong></p><p>设抛物线解析式为 y = ax² + bx + c。</p><p>由 A(0, 3) 代入得 c = 3。</p><p>由 B(1, 0) 代入：a + b + 3 = 0 …… ˆ1</p><p>由 C(3, 0) 代入：9a + 3b + 3 = 0 …… ˆ2</p><p>由 ˆ2 − 3×ˆ1 得：6a − 6 = 0，解得 a = 1。</p><p>代入 ˆ1 得 b = −4。</p><p><strong>答：y = x² − 4x + 3</strong></p><p><strong>【方法提炼】</strong> 三点定抛物线，优先观察特殊点（与 y 轴交点直接得 c，与 x 轴交点可用交点式）。</p><hr><h2 id="案例-2-利用交点式求解析式-⭐" tabindex="-1">案例 2：利用交点式求解析式 ⭐ <a class="header-anchor" href="#案例-2-利用交点式求解析式-⭐" aria-label="Permalink to &quot;案例 2：利用交点式求解析式 ⭐&quot;">​</a></h2><p><img src="'+o+'" alt="案例2示意图"></p><p><strong>【题目】</strong> 抛物线与 x 轴交于点 (−1, 0) 和 (3, 0)，且过点 (1, 4)，求解析式。</p><p><strong>【解析】</strong></p><p>设交点式：y = a(x + 1)(x − 3)</p><p>将 (1, 4) 代入：4 = a(1 + 1)(1 − 3) = a × 2 × (−2) = −4a</p><p>解得 a = −1。</p><p>展开：y = −(x + 1)(x − 3) = −x² + 2x + 3</p><p><strong>答：y = −x² + 2x + 3</strong></p><p><strong>【方法提炼】</strong> 已知与 x 轴两交点时，交点式比一般式更快捷。</p><hr><h2 id="案例-3-顶点式与图象变换-⭐⭐" tabindex="-1">案例 3：顶点式与图象变换 ⭐⭐ <a class="header-anchor" href="#案例-3-顶点式与图象变换-⭐⭐" aria-label="Permalink to &quot;案例 3：顶点式与图象变换 ⭐⭐&quot;">​</a></h2><p><img src="'+n+'" alt="案例3示意图"></p><p><strong>【题目】</strong> 将抛物线 y = x² 先向右平移 2 个单位，再向上平移 1 个单位，求新的抛物线解析式及顶点坐标。</p><p><strong>【解析】</strong></p><p>向右平移 2 个单位：y = (x − 2)²</p><p>再向上平移 1 个单位：y = (x − 2)² + 1</p><p>顶点坐标为 (2, 1)。</p><p><strong>答：y = (x − 2)² + 1，顶点 (2, 1)</strong></p><p><strong>【方法提炼】</strong> 平移口诀：左加右减（对 x），上加下减（对整体）。用顶点式最直观。</p><hr><h2 id="案例-4-二次函数与不等式-⭐⭐" tabindex="-1">案例 4：二次函数与不等式 ⭐⭐ <a class="header-anchor" href="#案例-4-二次函数与不等式-⭐⭐" aria-label="Permalink to &quot;案例 4：二次函数与不等式 ⭐⭐&quot;">​</a></h2><p><img src="'+e+'" alt="案例4示意图"></p><p><strong>【题目】</strong> 抛物线 y = −x² + 2x + 3，求： （1）y &gt; 0 时 x 的取值范围； （2）y ≤ 0 时 x 的取值范围。</p><p><strong>【解析】</strong></p><p>令 y = 0：−x² + 2x + 3 = 0，即 x² − 2x − 3 = 0</p><p>(x − 3)(x + 1) = 0，解得 x = 3 或 x = −1。</p><p>抛物线开口向下，与 x 轴交于 (−1, 0) 和 (3, 0)。</p><p>（1）y &gt; 0：−1 &lt; x &lt; 3</p><p>（2）y ≤ 0：x ≤ −1 或 x ≥ 3</p><p><strong>答：（1）−1 &lt; x &lt; 3；（2）x ≤ −1 或 x ≥ 3</strong></p><p><strong>【方法提炼】</strong> 开口向上时两交点之间 y &lt; 0；开口向下时两交点之间 y &gt; 0。</p><hr><h2 id="案例-5-面积最值问题-⭐⭐" tabindex="-1">案例 5：面积最值问题 ⭐⭐ <a class="header-anchor" href="#案例-5-面积最值问题-⭐⭐" aria-label="Permalink to &quot;案例 5：面积最值问题 ⭐⭐&quot;">​</a></h2><p><img src="'+d+'" alt="案例5示意图"></p><p><strong>【题目】</strong> 抛物线 y = −x² + 4x 与 x 轴围成的封闭区域内，求内接矩形面积的最大值（矩形一边在 x 轴上，对边在抛物线上）。</p><p><strong>【解析】</strong></p><p>抛物线与 x 轴交点：−x² + 4x = 0，x(4 − x) = 0，得 x = 0 或 x = 4。顶点 (2, 4)。</p><p>设矩形在 x 轴上的顶点为 (x, 0)（0 &lt; x &lt; 2），则矩形宽为 2x（关于对称轴对称），高为 −x² + 4x。</p><p>面积 S = 2x × (−x² + 4x) = −2x³ + 8x²</p><p>求导（或配方法分析）：</p><p>S&#39; = −6x² + 16x = −2x(3x − 8) = 0</p><p>解得 x = 8/3（0 &lt; 8/3 &lt; 2 不成立，应取 0 &lt; x &lt; 2 内的值）。</p><p>换方法：设对称矩形，顶点 (2−t, 0) 和 (2+t, 0)，0 &lt; t &lt; 2。</p><p>高 h = −(2−t)² + 4(2−t) = −4 + 4t − t² + 8 − 4t = 4 − t²</p><p>S = 2t(4 − t²) = 8t − 2t³</p><p>S&#39; = 8 − 6t² = 0，t² = 4/3，t = 2√3/3</p><p>S = 8 × 2√3/3 − 2 × 8×3√3/27 = 16√3/3 − 16√3/9 = 32√3/9</p><p><strong>答：最大面积为 32√3/9</strong></p><p><strong>【方法提炼】</strong> 面积最值问题中，利用对称性设变量（以对称轴为中心），再求函数最值。</p><hr><h2 id="案例-6-二次函数与一次函数交点-⭐⭐⭐" tabindex="-1">案例 6：二次函数与一次函数交点 ⭐⭐⭐ <a class="header-anchor" href="#案例-6-二次函数与一次函数交点-⭐⭐⭐" aria-label="Permalink to &quot;案例 6：二次函数与一次函数交点 ⭐⭐⭐&quot;">​</a></h2><p><img src="'+g+'" alt="案例6示意图"></p><p><strong>【题目】</strong> 抛物线 y = x² − 2x − 3 与直线 y = x + 1 的交点为 A、B，求 ▵AOB 的面积（O 为原点）。</p><p><strong>【解析】</strong></p><p>联立方程：x² − 2x − 3 = x + 1</p><p>x² − 3x − 4 = 0，(x − 4)(x + 1) = 0</p><p>x = 4 时 y = 5，即 A(4, 5)；x = −1 时 y = 0，即 B(−1, 0)。</p><p>B 在 x 轴上，以 OB 为底，OB = 1，A 到 x 轴距离为 5。</p><p>S▵AOB = 1/2 × 1 × 5 = 5/2</p><p><strong>答：▵AOB 面积为 5/2</strong></p><p><strong>【方法提炼】</strong> 两函数图象交点问题，联立方程组求解。求面积时选坐标轴上的点为底边更方便。</p><hr><h2 id="案例-7-动点与二次函数最值-⭐⭐⭐" tabindex="-1">案例 7：动点与二次函数最值 ⭐⭐⭐ <a class="header-anchor" href="#案例-7-动点与二次函数最值-⭐⭐⭐" aria-label="Permalink to &quot;案例 7：动点与二次函数最值 ⭐⭐⭐&quot;">​</a></h2><p><img src="'+l+'" alt="案例7示意图"></p><p><strong>【题目】</strong> 如图，抛物线 y = −1/2 x² + 3/2 x + 2 与 x 轴交于 A、B 两点（A 在 B 左侧），与 y 轴交于点 C。点 P 是抛物线上的动点，当 ▵PAC 面积最大时，求点 P 的坐标。</p><p><strong>【解析】</strong></p><p>A、B 坐标：令 y = 0，−1/2 x² + 3/2 x + 2 = 0，即 x² − 3x − 4 = 0</p><p>(x − 4)(x + 1) = 0，A(−1, 0)，B(4, 0)。</p><p>C 坐标：x = 0，y = 2，C(0, 2)。</p><p>AC 所在直线：过 A(−1, 0) 和 C(0, 2)，y = 2x + 2。</p><p>设 P(x, −1/2 x² + 3/2 x + 2)，P 到直线 AC 的距离：</p><p>S▵PAC = 1/2 × AC × d</p><p>但更方便用&quot;铅垂高&quot;法：S = 1/2 × |xP − xA| × |yP − yAC|</p><p>yAC = 2x + 2（当 x = xP 时）</p><p>S = 1/2 × |x − (−1)| × |(−1/2 x² + 3/2 x + 2) − (2x + 2)|</p><p>= 1/2 × (x + 1) × |−1/2 x² − 1/2 x|</p><p>= 1/2 × (x + 1) × 1/2 x(x + 1)（x 在 A、B 之间时 −1/2 x² − 1/2 x ≥ 0）</p><p>= 1/4 x(x + 1)²</p><p>对 S 求最值（x ≥ 0，x ≤ 4）：</p><p>S = 1/4 x(x² + 2x + 1) = 1/4(x³ + 2x² + x)</p><p>令 S&#39; = 1/4(3x² + 4x + 1) = 0</p><p>3x² + 4x + 1 = 0，(3x + 1)(x + 1) = 0，x = −1/3 或 x = −1（均不在范围内）</p><p>在 x ∈ [0, 4] 上 S 单调递增，x = 4 时 S 最大。</p><p>P(4, 0) 即点 B，但此时 ▵PAC 退化（P 在 x 轴上）。</p><p>需要限制 P 不在 x 轴上，则取 x 接近 4 时面积最大。</p><p>实际上，应在 −1 &lt; x &lt; 0 段考察：</p><p>x ∈ (−1, 0) 时，S = 1/4 x(x + 1)² &lt; 0，取绝对值。</p><p>修正：用坐标法。</p><p>S▵PAC = 1/2 |xA(yP − yC) + xP(yC − yA) + xC(yA − yP)|</p><p>= 1/2 |(−1)(yP − 2) + x(2 − 0) + 0(0 − yP)|</p><p>= 1/2 |−yP + 2 + 2x|</p><p>= 1/2 |2x − yP + 2|</p><p>= 1/2 |2x − (−1/2 x² + 3/2 x + 2) + 2|</p><p>= 1/2 |1/2 x² + 1/2 x|</p><p>= 1/4 |x² + x|</p><p>= 1/4 |x(x + 1)|</p><p>在 x ∈ [−1, 4] 上：</p><p>x ∈ [−1, 0] 时 |x(x+1)| = −x(x+1) = −x² − x</p><p>x ∈ [0, 4] 时 |x(x+1)| = x(x+1) = x² + x</p><p>两段分别求最值：</p><p>段1：S = 1/4(−x² − x)，顶点 x = −1/2，S = 1/4 × 1/4 = 1/16</p><p>段2：S = 1/4(x² + x)，在 x = 4 时 S = 1/4 × 20 = 5</p><p>x = 4 时 P(4, 0) = B 点，▵退化为线段，排除。</p><p>取 x 接近 4 但不等于 4，面积接近 5。</p><p>实际考试中取 x = 4 时 P 与 B 重合，需检查题意是否排除。</p><p>若 P 不同于 A、B，则 x 接近 4，取 x = 3 时 y = −9/2 + 9/2 + 2 = 2，P(3, 2)，S = 1/4 × 12 = 3。</p><p><strong>答：当 x = −1/2 时 P(−1/2, 17/8)，最大面积 1/16（左侧段）；右侧段面积在 x 接近 4 时趋于 5 但三角形退化。题意若限制 P 在 AC 上方弧段，则最大面积点为 P(−1/2, 17/8)。</strong></p><p><strong>【方法提炼】</strong> 动点面积最值，用坐标法（行列式公式）比铅垂高法更通用、不易出错。</p><hr><h2 id="案例-8-二次函数与平行四边形存在性-⭐⭐⭐⭐" tabindex="-1">案例 8：二次函数与平行四边形存在性 ⭐⭐⭐⭐ <a class="header-anchor" href="#案例-8-二次函数与平行四边形存在性-⭐⭐⭐⭐" aria-label="Permalink to &quot;案例 8：二次函数与平行四边形存在性 ⭐⭐⭐⭐&quot;">​</a></h2><p><img src="'+i+'" alt="案例8示意图"></p><p><strong>【题目】</strong> 抛物线 y = −x² + 2x + 3 与 x 轴交于 A、B，与 y 轴交于 C。抛物线上是否存在点 P，使 A、B、C、P 为平行四边形的四个顶点？若存在，求 P 坐标。</p><p><strong>【解析】</strong></p><p>A(−1, 0)，B(3, 0)，C(0, 3)。</p><p>平行四边形条件：对角线互相平分（中点重合）。</p><p>情况1：AB 为对角线，则 AB 中点 M(1, 0)，CP 中点也为 M(1, 0)。</p><p>P 关于 M 的对称点：P(2, −3)。</p><p>验证 P 在抛物线上：y = −4 + 4 + 3 = 3 ≠ −3，不在抛物线上。</p><p>情况2：AC 为对角线，AC 中点 N(−1/2, 3/2)，BP 中点也为 N。</p><p>P(2 × (−1/2) − 3, 2 × 3/2 − 0) = (−4, 3)。</p><p>验证：y = −16 − 8 + 3 = −21 ≠ 3，不在抛物线上。</p><p>情况3：BC 为对角线，BC 中点 L(3/2, 3/2)，AP 中点也为 L。</p><p>P(2 × 3/2 − (−1), 2 × 3/2 − 0) = (4, 3)。</p><p>验证：y = −16 + 8 + 3 = −5 ≠ 3，不在抛物线上。</p><p>三种情况 P 均不在抛物线上。</p><p><strong>答：不存在满足条件的点 P。</strong></p><p><strong>【方法提炼】</strong> 平行四边形存在性问题，用&quot;对角线互相平分&quot;条件列方程，再验证点是否在抛物线上。3 条对角线组合对应 3 种情况，需逐一检验。</p><hr><h2 id="案例-9-二次函数背景下的线段最值-⭐⭐⭐⭐" tabindex="-1">案例 9：二次函数背景下的线段最值 ⭐⭐⭐⭐ <a class="header-anchor" href="#案例-9-二次函数背景下的线段最值-⭐⭐⭐⭐" aria-label="Permalink to &quot;案例 9：二次函数背景下的线段最值 ⭐⭐⭐⭐&quot;">​</a></h2><p><img src="'+c+'" alt="案例9示意图"></p><p><strong>【题目】</strong> 抛物线 y = x² − 2x − 3 与 x 轴交于 A、B（A 左 B 右），与 y 轴交于 C，顶点为 D。点 M 在抛物线的对称轴上，求 MC + MD 的最小值。</p><p><strong>【解析】</strong></p><p>A(−1, 0)，B(3, 0)，对称轴 x = 1。</p><p>C(0, −3)，D(1, −4)。</p><p>M 在 x = 1 上，设 M(1, m)。</p><p>MC = √((1−0)² + (m+3)²) = √(1 + (m+3)²)</p><p>MD = |m + 4|</p><p>MC + MD = √(1 + (m+3)²) + |m + 4|</p><p>利用几何法：将 D 关于对称轴反射——但 D 已在对称轴上，反射后仍是 D。</p><p>换思路：C 关于对称轴 x = 1 的对称点 C&#39;(2, −3)。</p><p>MC = MC&#39;（M 在对称轴上），MC + MD = MC&#39; + MD。</p><p>MC&#39; + MD ≥ C&#39;D（三点共线取等号）。</p><p>C&#39;D = √((2−1)² + (−3+4)²) = √(1 + 1) = √2</p><p><strong>答：MC + MD 的最小值为 √2，当 M 在 C&#39;D 连线上时取得。</strong></p><p>M 坐标：直线 C&#39;D 过 C&#39;(2,−3) 和 D(1,−4)，斜率 = (−3+4)/(2−1) = 1，方程 y = x − 5。</p><p>x = 1 时 y = −4，M(1, −4) = D。</p><p>验证：MC + MD = √(1 + 1) + 0 = √2。✓</p><p><strong>【方法提炼】</strong> 对称轴上动点求折线段最小值，核心方法：反射（利用对称性把折线变直线），再用&quot;两点之间线段最短&quot;。</p><hr><h2 id="案例-10-二次函数综合压轴-⭐⭐⭐⭐" tabindex="-1">案例 10：二次函数综合压轴 ⭐⭐⭐⭐ <a class="header-anchor" href="#案例-10-二次函数综合压轴-⭐⭐⭐⭐" aria-label="Permalink to &quot;案例 10：二次函数综合压轴 ⭐⭐⭐⭐&quot;">​</a></h2><p><img src="'+h+'" alt="案例10示意图"></p><p><strong>【题目】</strong> （广州中考风格压轴题）抛物线 y = ax² + bx + c 经过 A(−1, 0)、B(3, 0)、C(0, 3) 三点。</p><p>（1）求抛物线解析式；</p><p>（2）点 P 是第一象限内抛物线上的动点，过 P 作 PQ ⊥ x 轴于 Q，当 ▵APQ 面积最大时，求 P 的坐标及最大面积；</p><p>（3）在（2）的条件下，抛物线的对称轴上是否存在点 M，使 ▵MAP 是等腰三角形？若存在，求 M 的坐标。</p><p><strong>【解析】</strong></p><p><strong>（1）</strong> 由 A、B、C 三点：</p><p>设 y = a(x + 1)(x − 3)，代入 C(0, 3)：3 = a × 1 × (−3) = −3a，a = −1。</p><p>y = −(x + 1)(x − 3) = −x² + 2x + 3</p><p><strong>答：y = −x² + 2x + 3</strong></p><p><strong>（2）</strong> 设 P(x, −x² + 2x + 3)，0 &lt; x &lt; 3，Q(x, 0)。</p><p>AQ = x − (−1) = x + 1，PQ = −x² + 2x + 3。</p><p>S▵APQ = 1/2 × AQ × PQ = 1/2(x + 1)(−x² + 2x + 3)</p><p>= 1/2(−x³ + 2x² + 3x − x² + 2x + 3)</p><p>= 1/2(−x³ + x² + 5x + 3)</p><p>求最值：对 S 关于 x 求极值点</p><p>S&#39; = 1/2(−3x² + 2x + 5) = 0</p><p>3x² − 2x − 5 = 0，(3x − 5)(x + 1) = 0</p><p>x = 5/3（x = −1 舍去）</p><p>P(5/3, −25/9 + 10/3 + 3) = (5/3, −25/9 + 30/9 + 27/9) = (5/3, 32/9)</p><p>S = 1/2 × 8/3 × 32/9 = 1/2 × 256/27 = 128/27</p><p><strong>答：P(5/3, 32/9)，最大面积 128/27</strong></p><p><strong>（3）</strong> 对称轴 x = 1，设 M(1, m)。</p><p>A(−1, 0)，P(5/3, 32/9)。</p><p>MA² = (1+1)² + m² = 4 + m²</p><p>MP² = (1 − 5/3)² + (m − 32/9)² = 4/9 + (m − 32/9)²</p><p>AP² = (5/3+1)² + (32/9)² = 64/9 + 1024/81 = 576/81 + 1024/81 = 1600/81</p><p>等腰三角形分三种情况：</p><p><strong>MA = MP：</strong> 4 + m² = 4/9 + m² − 64m/9 + 1024/81</p><p>4 − 4/9 = −64m/9 + 1024/81</p><p>32/9 = (−576m + 1024)/81</p><p>288 = −576m + 1024</p><p>576m = 736</p><p>m = 736/576 = 23/18</p><p>M₁(1, 23/18)</p><p><strong>MA = AP：</strong> 4 + m² = 1600/81</p><p>m² = 1600/81 − 4 = 1276/81</p><p>m = ±√1276/9 = ±2√319/9</p><p>M₂(1, 2√319/9)，M₃(1, −2√319/9)</p><p><strong>MP = AP：</strong> 4/9 + (m − 32/9)² = 1600/81</p><p>(m − 32/9)² = 1600/81 − 4/9 = 1564/81</p><p>m − 32/9 = ±√1564/9</p><p>m = 32/9 ± √1564/9 = (32 ± 2√391)/9</p><p>M₄(1, (32 + 2√391)/9)，M₅(1, (32 − 2√391)/9)</p><p><strong>答：共 5 个点满足条件。M₁(1, 23/18)、M₂(1, 2√319/9)、M₃(1, −2√319/9)、M₄(1, (32+2√391)/9)、M₅(1, (32−2√391)/9)</strong></p><p><strong>【方法提炼】</strong> 等腰三角形存在性问题，分 MA=MP、MA=AP、MP=AP 三种情况，列出方程逐一求解。注意检验三点不共线。</p><hr><h2 id="方法总结" tabindex="-1">方法总结 <a class="header-anchor" href="#方法总结" aria-label="Permalink to &quot;方法总结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>题型</th><th>核心方法</th><th>难度</th></tr></thead><tbody><tr><td>求解析式</td><td>待定系数法（一般式/交点式/顶点式）</td><td>⭐</td></tr><tr><td>图象变换</td><td>平移口诀：左加右减、上加下减</td><td>⭐⭐</td></tr><tr><td>不等式</td><td>借助图象，开口方向判断两交点间符号</td><td>⭐⭐</td></tr><tr><td>面积最值</td><td>坐标法/铅垂高法 + 二次函数最值</td><td>⭐⭐⭐</td></tr><tr><td>交点问题</td><td>联立方程组</td><td>⭐⭐⭐</td></tr><tr><td>动点最值</td><td>设参建函数 → 求最值</td><td>⭐⭐⭐</td></tr><tr><td>平行四边形存在性</td><td>对角线互相平分 → 验证在抛物线上</td><td>⭐⭐⭐⭐</td></tr><tr><td>线段最值</td><td>对称反射 + 两点之间线段最短</td><td>⭐⭐⭐⭐</td></tr><tr><td>等腰三角形存在性</td><td>分三种情况列方程</td><td>⭐⭐⭐⭐</td></tr></tbody></table>',216)])])}const B=t(m,[["render",P]]);export{_ as __pageData,B as default};
